def gen(rng, size):
    # Build a valid tree: each entry's depth <= parent_depth + 1
    parts = []
    cur_depth = 0
    for i in range(size):
        # depth can stay, go one deeper, or come back up
        if cur_depth == 0:
            depth = 0
        else:
            step = rng.choice([-1, 0, 1])
            depth = max(0, min(3, cur_depth + step))
        # only go deeper if parent exists
        if depth > cur_depth + 1:
            depth = cur_depth + 1
        tabs = '\t' * depth
        if i == size - 1 or rng.random() < 0.35:
            parts.append(tabs + 'file' + str(i) + '.txt')
            cur_depth = max(0, depth - 1)
        else:
            parts.append(tabs + 'dir' + str(i))
            cur_depth = depth
    if not parts:
        parts = ['root']
    return ['\n'.join(parts)]

