class Solution:
    def lengthLongestPath(self, input: str) -> int:
        # Build actual path strings tracking depth -> cumulative path length
        lines = input.split('\n')
        # depth_len[d] = length of path string up to and including depth d
        depth_len = {-1: 0}
        best = 0
        for line in lines:
            depth = len(line) - len(line.lstrip('\t'))
            name = line[depth:]
            parent_len = depth_len.get(depth - 1, 0)
            cur_len = parent_len + (1 if depth > 0 else 0) + len(name)
            if '.' in name:
                best = max(best, cur_len)
            else:
                depth_len[depth] = cur_len
        return best

