var lengthLongestPath = function(input) {
    const stack = {};
    stack[-1] = 0;
    let best = 0;
    for (const line of input.split('\n')) {
        let depth = 0;
        while (depth < line.length && line[depth] === '\t') depth++;
        const name = line.slice(depth);
        const parentLen = (stack[depth - 1] !== undefined ? stack[depth - 1] : 0);
        const curLen = parentLen + (depth > 0 ? 1 : 0) + name.length;
        if (name.includes('.')) {
            best = Math.max(best, curLen);
        } else {
            stack[depth] = curLen;
        }
    }
    return best;
};
